import urllib.parse, pyodbc
from flask import Flask, make_response, render_template

app = Flask(__name__)

@app.route('/<column>/<value>') # http://<api url>/city/Berlin
def index(column="", value=""):
    # Create connection to DB. Connection string to Google Cloud SQL.
    conString = (
      'Driver={MySQL ODBC 5.3 Driver};'
      'Server=us-east1:test-db-796703;'
      'Database=Test;'
      'Uid=admin;'
      'Pwd=<PASSWORD>;'
      'Port=3306;'
    )

    con = pyodbc.connect(conString)
    cur = con.cursor() # creates a cursor object to execute the SQL query using connection variable created above
    
    sqlStatement = "Select * From MyTable Where ColumnName = '" + urllib.parse.quote_plus(value) +"';" # Using URI encoding of user input, for searching.
    
    print('sqlStatement: ' + sqlStatement) # This line will be visible in logs
    resultData = cur.execute(sqlStatement).fetchall()
    cur.close()
    
    return make_response(render_template("results.html", ColumnName=column, ValueEntered=value, RowsCounted=len(resultData), Data=resultData))

if __name__ == "__main__":
    app.run(debug = True)

